1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Edge cases / simplest
6	  it("empty item list → premium 5 G (only the processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result.results[0]).toEqual({ premium: 5 });
12	  });
13	
14	  // Base premiums for main items (each + 5 G fee)
15	  it("single sword → premium 105 G (100 base + 5 fee)", () => {
16	    const result = runScenario({
17	      customer: { yearsWithMHPCO: 0 },
18	      steps: [{ op: "quote", items: [{ type: "sword" }] }],
19	    });
20	    expect(result.results[0]).toEqual({ premium: 105 });
21	  });
22	  it("single amulet → premium 65 G (60 base + 5 fee)", () => {
23	    const result = runScenario({
24	      customer: { yearsWithMHPCO: 0 },
25	      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
26	    });
27	    expect(result.results[0]).toEqual({ premium: 65 });
28	  });
29	  it("single staff → premium 85 G (80 base + 5 fee)", () => {
30	    const result = runScenario({
31	      customer: { yearsWithMHPCO: 0 },
32	      steps: [{ op: "quote", items: [{ type: "staff" }] }],
33	    });
34	    expect(result.results[0]).toEqual({ premium: 85 });
35	  });
36	  it("single potion → premium 45 G (40 base + 5 fee)", () => {
37	    const result = runScenario({
38	      customer: { yearsWithMHPCO: 0 },
39	      steps: [{ op: "quote", items: [{ type: "potion" }] }],
40	    });
41	    expect(result.results[0]).toEqual({ premium: 45 });
42	  });
43	
44	  // Component pricing
45	  it("2 runes → 50 G base premium (55 G with fee)", () => {
46	    const result = runScenario({
47	      customer: { yearsWithMHPCO: 0 },
48	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
49	    });
50	    expect(result.results[0]).toEqual({ premium: 55 });
51	  });
52	  it("3 runes → 60 G base premium block (65 G with fee)", () => {
53	    const result = runScenario({
54	      customer: { yearsWithMHPCO: 0 },
55	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
56	    });
57	    expect(result.results[0]).toEqual({ premium: 65 });
58	  });
59	  it("4 runes → 100 G base premium no block (105 G with fee)", () => {
60	    const result = runScenario({
61	      customer: { yearsWithMHPCO: 0 },
62	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }] }],
63	    });
64	    expect(result.results[0]).toEqual({ premium: 105 });
65	  });
66	  it("7 runes → 175 G base premium (180 G with fee; no block since block requires exactly 3)", () => {
67	    const items = Array.from({ length: 7 }, () => ({ type: "rune" }));
68	    const result = runScenario({
69	      customer: { yearsWithMHPCO: 0 },
70	      steps: [{ op: "quote", items }],
71	    });
72	    expect(result.results[0]).toEqual({ premium: 180 });
73	  });
74	
75	  // "Alike" components clarification
76	  it("2 runes + 1 moonstone → 75 G base premium (80 G with fee; no block: different types)", () => {
77	    const result = runScenario({
78	      customer: { yearsWithMHPCO: 0 },
79	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }] }],
80	    });
81	    expect(result.results[0]).toEqual({ premium: 80 });
82	  });
83	  it("3 runes + 3 moonstones → 120 G base premium (125 G with fee; two separate blocks)", () => {
84	    const result = runScenario({
85	      customer: { yearsWithMHPCO: 0 },
86	      steps: [{ op: "quote", items: [
87	        { type: "rune" }, { type: "rune" }, { type: "rune" },
88	        { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
89	      ] }],
90	    });
91	    expect(result.results[0]).toEqual({ premium: 125 });
92	  });
93	
94	  // Item-specific modifiers
95	  it("cursed sword adds 50% risk surcharge → 100 + 50 = 150 base, 155 with fee", () => {
96	    const result = runScenario({
97	      customer: { yearsWithMHPCO: 0 },
98	      steps: [{ op: "quote", items: [{ type: "sword", cursed: true }] }],
99	    });
100	    expect(result.results[0]).toEqual({ premium: 155 });
101	  });
102	  it.todo("highly enchanted sword (enchantment 5) adds 30% surcharge → 130 base, 135 with fee");
103	  it.todo("sword with enchantment 4 → no high-enchantment surcharge (100 base, 105 with fee)");
104	  it.todo("cursed sword with enchantment 5 → both surcharges apply (100 + 50 + 30 = 180, 185 with fee)");
105	
106	  // Policy-wide modifiers
107	  it.todo("first insurance adds 10% to policy → sword 100 + 10 = 110, 115 with fee");
108	  it.todo("loyalty discount: customer with exactly 2 years → 20% off policy");
109	  it.todo("follow-up contract: second quote in scenario gets 15% discount");
110	
111	  // Modifier scope on multi-item policies
112	  it.todo("policy with cursed sword + plain amulet → cursed surcharge only on sword's base premium (160 + 50 = 210 before fee and other modifiers)");
113	
114	  // Rounding
115	  it.todo("premium calculation yielding 197.5 G → final premium 198 G (rounded up)");
116	
117	  // Integration examples
118	  it.todo("newcomer with cursed sword (steel, ench 3) → 165 G");
119	  it.todo("long-standing customer's second contract: cursed sword (steel, ench 7), 3 years → 160 G");
120	
121	  // Claim: standard reimbursement
122	  it.todo("regular sword damage 500 G → payout 400 G (deductible 100)");
123	  it.todo("rune damage 200 G → payout 100 G (no special clauses, deductible)");
124	
125	  // Enchantment threshold vs dragon material
126	  it.todo("dragon-material sword, enchantment 8, damage 1000 G → payout 400 G (50% rule + deductible)");
127	  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% wins, then deductible)");
128	  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (full reimbursement minus deductible)");
129	  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");
130	
131	  // Deductible per damage event
132	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible per item)");
133	
134	  // Multiple items of same type
135	  it.todo("policy covers two swords → insurance sum 2000, cap 4000");
136	  it.todo("two sword damages with two swords insured → each treated as separate damage with own deductible");
137	  it.todo("damages contain more entries of a type than insured (2 sword damages, 1 sword) → claim rejected (error)");
138	
139	  // Cap exhaustion
140	  it.todo("sword + amulet policy → insurance sum 1600, cap 3200");
141	  it.todo("cursed sword (premium with modifiers 165) → cap 2000 (based on unmodified insurance value)");
142	  it.todo("sword + 3 runes block → insurance sum 1750 (block discount affects premium only)");
143	  it.todo("sword cap 2000, two claims of 1500 each → first payout 1400 (cap 600 remaining), second payout 600 (cap 0)");
144	
145	  // Payout rounding
146	  it.todo("payout yielding 350.5 G → final payout 350 G (rounded down)");
147	
148	  // Edge cases / errors
149	  it.todo("quote with unknown item type → CLI exits non-zero, error to stderr");
150	  it.todo("claim references item not in policy → CLI exits non-zero, error to stderr");
151	  it.todo("claim contains damage with negative amount → CLI exits non-zero, error to stderr");
152	});
