1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteStep {
13	  op: "quote";
14	  items: Item[];
15	}
16	
17	export interface Damage {
18	  itemType: string;
19	  amount: number;
20	}
21	
22	export interface Incident {
23	  cause: string;
24	  damages: Damage[];
25	}
26	
27	export interface ClaimStep {
28	  op: "claim";
29	  policy: number;
30	  incident: Incident;
31	}
32	
33	export type Step = QuoteStep | ClaimStep;
34	
35	export interface Scenario {
36	  customer: Customer;
37	  steps: Step[];
38	}
39	
40	export interface QuoteResult {
41	  premium: number;
42	}
43	
44	export interface ClaimResult {
45	  payout: number;
46	  remainingCap: number;
47	}
48	
49	export type StepResult = QuoteResult | ClaimResult;
50	
51	export interface ScenarioResult {
52	  results: StepResult[];
53	}
54	
55	const PROCESSING_FEE = 5;
56	
57	const BASE_PREMIUM: Record<string, number> = {
58	  sword: 100,
59	  amulet: 60,
60	  staff: 80,
61	  potion: 40,
62	  rune: 25,
63	  moonstone: 25,
64	};
65	
66	const itemBasePremium = (item: Item): number => {
67	  const base = BASE_PREMIUM[item.type] ?? 0;
68	  const cursedSurcharge = item.cursed ? base * 0.5 : 0;
69	  return base + cursedSurcharge;
70	};
71	
72	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
73	const BLOCK_SIZE = 3;
74	const BLOCK_PREMIUM = 60;
75	
76	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
77	
78	const sumBasePremiums = (items: Item[]): number =>
79	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
80	
81	const groupByType = (items: Item[]): Item[][] => {
82	  const byType = new Map<string, Item[]>();
83	  for (const item of items) {
84	    const group = byType.get(item.type) ?? [];
85	    group.push(item);
86	    byType.set(item.type, group);
87	  }
88	  return [...byType.values()];
89	};
90	
91	const groupPremium = (group: Item[]): number =>
92	  group.length === BLOCK_SIZE ? BLOCK_PREMIUM : sumBasePremiums(group);
93	
94	const componentsPremium = (components: Item[]): number =>
95	  groupByType(components).reduce((total, group) => total + groupPremium(group), 0);
96	
97	const itemsBasePremium = (items: Item[]): number =>
98	  componentsPremium(items.filter(isComponent)) +
99	  sumBasePremiums(items.filter((item) => !isComponent(item)));
100	
101	const quotePremium = (items: Item[]): number =>
102	  itemsBasePremium(items) + PROCESSING_FEE;
103	
104	export const runScenario = (scenario: Scenario): ScenarioResult => {
105	  const results = scenario.steps.map((step): StepResult => {
106	    if (step.op === "quote") {
107	      return { premium: quotePremium(step.items) };
108	    }
109	    return { payout: 0, remainingCap: 0 };
110	  });
111	  return { results };
112	};
